def _extract_linguistic_signatures(text: str) -> dict:
    return {
        'complexity': len(text.split()) / len(set(text.split())),
        'sentiment_markers': len(re.findall(r'\b(very|extremely|deeply)\b', text.lower())),
        'first_person_references': len(re.findall(r'\b(i|me|my|mine)\b', text.lower()))
    }

def _assess_emotional_tone(text: str) -> float:
    positive_words = ['happy', 'excited', 'joy', 'love', 'great']
    negative_words = ['sad', 'angry', 'frustrated', 'upset', 'bad']
    
    pos_count = sum(text.lower().count(word) for word in positive_words)
    neg_count = sum(text.lower().count(word) for word in negative_words)
    
    return (pos_count - neg_count) / (pos_count + neg_count + 1)

def _determine_interaction_modality(text: str) -> str:
    modality_indicators = {
        'analytical': ['because', 'therefore', 'hypothesis'],
        'emotional': ['feel', 'sense', 'emotion'],
        'creative': ['imagine', 'create', 'dream']
    }
    
    for mode, keywords in modality_indicators.items():
        if any(keyword in text.lower() for keyword in keywords):
            return mode
    
    return 'neutral'

